let validPriorities = ["High", "Medium", "Low"];
let emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

items.forEach(item => {
    item.json.Error = "";        // initialize error
    item.json.Rejected = false;  // initialize rejected flag

    // Validate email
    if (!emailRegex.test(item.json.Email)) {
        item.json.Error += "Invalid Email; ";
        item.json.Rejected = true;
    }

    // Validate priority
    if (!validPriorities.includes(item.json.Priority)) {
        item.json.Error += "Invalid Priority; ";
        item.json.Rejected = true;
    }
});

return items;

items.forEach(item => {
    item.json.Name = item.json.Name.trim();
    item.json.Email = item.json.Email.trim().toLowerCase();
    item.json.IssueType = item.json.IssueType.trim().toLowerCase();
    item.json.Priority = item.json.Priority.trim();
    item.json.Description = item.json.Description.trim();
});
return items;

items.forEach((item, index) => {
    item.json.TicketID = "TICKET-" + (1000 + index);
});
return items;

items.forEach(item => {
    switch(item.json.IssueType) {
        case "wifi":
            item.json.Team = "Network";
            break;
        case "login":
            item.json.Team = "IT Support";
            break;
        case "software":
            item.json.Team = "Applications";
            break;
        case "hardware":
            item.json.Team = "Infrastructure";
            break;
        default:
            item.json.Team = "General";
    }
});
return items;

items.forEach(item => {
    let slaHours;
    switch(item.json.Priority) {
        case "High": slaHours = 4; break;
        case "Medium": slaHours = 24; break;
        case "Low": slaHours = 72; break;
    }
    let submitted = new Date(item.json.Timestamp);
    let deadline = new Date(submitted.getTime() + slaHours*60*60*1000);
    item.json.SLA_Deadline = deadline.toISOString();
});
return items;

const fields = ["TicketID","Name","Email","IssueType","Priority","Description","Team","SLA_Deadline"];

const csv = items.map(i => fields.map(f => `"${i.json[f]}"`).join(",")).join("\n");

// Add header
const header = fields.join(",");
const content = header + "\n" + csv;

items[0].binary = {};
items[0].binary.data = {
    data: Buffer.from(content),
    mimeType: 'text/csv',
    fileName: 'Processed_Tickets.csv'
};

return [items[0]];;

let total = items.length;
let high = items.filter(i => i.json.Priority === "High").length;
let medium = items.filter(i => i.json.Priority === "Medium").length;
let low = items.filter(i => i.json.Priority === "Low").length;

return [
    { json: { TotalTickets: total, High: high, Medium: medium, Low: low } }
];

let teamCounts = {
    "Network": 0,
    "IT Support": 0,
    "Applications": 0,
    "Infrastructure": 0,
    "General": 0
};

items.forEach(item => {
    const team = item.json.Team;
    if (teamCounts.hasOwnProperty(team)) {
        teamCounts[team]++;
    } else {
        teamCounts["General"]++;
    }
});

let output = [];
for (const [team, count] of Object.entries(teamCounts)) {
    output.push({ json: { Team: team, Tickets: count } });
}

return output;
